1	const dotenv = require('dotenv');
2	const path = require('path');
3	const Joi = require('joi');
4	
5	dotenv.config({ path: path.join(__dirname, '../../.env') });
6	
7	const envVarsSchema = Joi.object()
8	  .keys({
9	    NODE_ENV: Joi.string().valid('production', 'development', 'test').required(),
10	    PORT: Joi.number().default(3000),
11	    MONGODB_URL: Joi.string().required().description('Mongo DB url'),
12	    REDIS_URL: Joi.string().required().description('Redis url'),
13	    JWT_SECRET: Joi.string().required().description('JWT secret key'),
14	    JWT_ACCESS_EXPIRATION_MINUTES: Joi.number().default(120).description('access token expiry in minutes'),
15	    JWT_REFRESH_EXPIRATION_DAYS: Joi.number().default(1).description('refresh token expiry in days'),
16	  })
17	  .unknown();
18	
19	const { value: envVars, error } = envVarsSchema.prefs({ errors: { label: 'key' } }).validate(process.env);
20	
21	if (error) {
22	  throw new Error(`Config validation error: ${error.message}`);
23	}
24	
25	module.exports = {
26	  env: envVars.NODE_ENV,
27	  port: envVars.PORT,
28	  mongoose: {
29	    url: envVars.MONGODB_URL + (envVars.NODE_ENV === 'test' ? '-test' : ''),
30	  },
31	  redis: {
32	    url: envVars.REDIS_URL,
33	  },
34	  jwt: {
35	    secret: envVars.JWT_SECRET,
36	    accessExpirationMinutes: envVars.JWT_ACCESS_EXPIRATION_MINUTES,
37	    refreshExpirationDays: envVars.JWT_REFRESH_EXPIRATION_DAYS,
38	  },
39	};
